#include<bits/stdc++.h>
#define LL long long
#define Uint unsigned int
#define ULL unsigned LL
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 1e5+5;
set<int> s;queue<int> q[N];
int T,m,n,k,now,a[N],c[N],p[N],Cnt;
void Init(){
    for(int i=1;i<=m;i++)while(!q[i].empty())q[i].pop();
    for(int i=1;i<=m;i++)c[i]=0;now=1,Cnt=0,s.clear();return;
}
bool Sol(){
    for(int i=1;i<=n;i++)c[a[i]]++;
    for(int i=1;i<=m;i++){
        int tl=i+k-1;
        if(tl<=m){
            c[tl]-=q[tl].size();
            while(!q[tl].empty())s.erase(q[tl].front()),q[tl].pop();
        }
        while(c[i]){
            int x=(now<=n?now:p[Cnt--]);
            if(s.size()==k){
                if(now>n)return 0;auto it=s.begin();
                p[++Cnt]=(*it),q[a[*it]].pop(),s.erase(*it);
            }
            if(a[x]<=tl)c[a[x]]--;
            else s.insert(x),q[a[x]].push(x);
            now=min(now+1,n+1);
        }
    }
    return 1;
}
int main(){
    cin>>T;
    while(T--){
        cin>>m>>n>>k;Init();
        for(int i=1;i<=n;i++)cin>>a[i];
        if(Sol())cout<<"YES\n";else cout<<"NO\n";
    }
    return 0;
}
